/// <summary>
/// lookup for default serial number - Abhinav
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(EcoResProductDetailsExtended, ETGDefaultSerialNumber), FormControlEventType::Lookup)]
public static void ETGDefaultSerialNumber_OnLookup(FormControl sender, FormControlEventArgs e)
{
    FormControlCancelableSuperEventArgs cancelEventArgs = e as FormControlCancelableSuperEventArgs;
    cancelEventArgs.cancelSuperCall();

    Query query = new Query();
    QueryBuildDataSource queryBuildDataSource;
    QueryBuildRange queryBuildRange;
    SysTableLookup sysTableLookup =
        SysTableLookup::newParameters(tableNum(InventSerial), sender);

    sysTableLookup.addLookupField(fieldNum(InventSerial,InventSerialId));
    sysTableLookup.addLookupField(fieldNum(InventSerial,Description));

    InventTable inventTable = sender.formRun().dataSource(1).cursor();
    queryBuildDataSource = query.addDataSource(tableNum(InventSerial));
    queryBuildDataSource.addRange(fieldNum(InventSerial,ItemId)).value(queryValue(inventTable.ItemId));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}
